function report = runSgmOptimizationBenchmark(options)
%RUNSGMOPTIMIZATIONBENCHMARK Gate vectorized in-memory SGM.
%
% A deterministic complete procedural cost volume includes nonuniform height
% labels, all-invalid path resets, and label-specific invalid candidates.
% The current pixel/path recurrence remains the numerical reference.
%
% Traceability: algo/main.tex Sec. 5.6 and Eqs. (71)--(75);
% implementation plan Stage C4.

arguments
    options.ImageSize (1, 2) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = [512, 512]
    options.LabelCount (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBeGreaterThanOrEqual( ...
        options.LabelCount, 3)} = 35
    options.WorkingPrecision (1, 1) string ...
        {mustBeMember(options.WorkingPrecision, ...
        ["single", "double"])} = "single"
    options.DirectionCount (1, 1) double ...
        {mustBeMember(options.DirectionCount, [4, 8])} = 8
    options.PenaltyPerMetre (1, 1) double ...
        {mustBeFinite, mustBeNonnegative} = 0.02
    options.MaximumPenalty (1, 1) double ...
        {mustBeFinite, mustBeNonnegative} = 0.2
    options.VectorizedRepetitions (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = 3
    options.MinimumSpeedup (1, 1) double ...
        {mustBeFinite, mustBeNonnegative} = 5
    options.OutputFile (1, 1) string = ""
end

rngState = rng;
cleanup = onCleanup(@() rng(rngState));
rng(20260718, "twister");
[nr, nc] = deal(options.ImageSize(1), options.ImageSize(2));
u = linspace(-1, 1, options.LabelCount);
z = 60 .* sign(u) .* abs(u) .^ 1.15;
[x, y] = meshgrid(1:nc, 1:nr);
truth = 18 .* sin(2 .* pi .* x ./ max(nc, 2)) ...
    .* cos(2 .* pi .* y ./ max(nr, 2));
cost = zeros(nr, nc, options.LabelCount, options.WorkingPrecision);
for k = 1:options.LabelCount
    c = ((z(k) - truth) ./ 60) .^ 2 ...
        + 0.002 .* rand(nr, nc);
    c(mod(y + 2 .* x + 3 .* k, 97) == 0) = NaN;
    cost(:, :, k) = cast(c, options.WorkingPrecision);
end
reset = false(nr, nc);
reset(1:min(2, nr), :) = true;
reset(:, 1:min(2, nc)) = true;
if nc >= 20
    reset(:, round(nc ./ 2)) = true;
end
cost(repmat(reset, 1, 1, options.LabelCount)) = NaN;

warmRows = 1:min(nr, 32);
warmColumns = 1:min(nc, 40);
warmCost = cost(warmRows, warmColumns, :);
HeightSgm.aggregate(warmCost, z, ...
    PenaltyPerMetre=options.PenaltyPerMetre, ...
    MaximumPenalty=options.MaximumPenalty, ...
    DirectionCount=options.DirectionCount);
HeightSgm.aggregateVectorized(warmCost, z, ...
    PenaltyPerMetre=options.PenaltyPerMetre, ...
    MaximumPenalty=options.MaximumPenalty, ...
    DirectionCount=options.DirectionCount);

reference = HeightSgm.aggregate(cost, z, ...
    PenaltyPerMetre=options.PenaltyPerMetre, ...
    MaximumPenalty=options.MaximumPenalty, ...
    DirectionCount=options.DirectionCount);
elapsed = zeros(options.VectorizedRepetitions, 1);
for k = 1:options.VectorizedRepetitions
    timer = tic;
    candidate = HeightSgm.aggregateVectorized(cost, z, ...
        PenaltyPerMetre=options.PenaltyPerMetre, ...
        MaximumPenalty=options.MaximumPenalty, ...
        DirectionCount=options.DirectionCount);
    elapsed(k) = toc(timer);
end
comparison = HeightSweepEquivalence.compare( ...
    reference.AggregatedCost, candidate.AggregatedCost, ...
    CostTolerance=0, TieTolerance=0);
referenceSeconds = reference.RuntimeSeconds(1);
vectorizedSeconds = median(elapsed, "all");
speedup = referenceSeconds ./ vectorizedSeconds;
allPass = all([comparison.Pass, ...
    speedup >= options.MinimumSpeedup]);
report = struct( ...
    "ImageSize", options.ImageSize, ...
    "HeightLabelsMetres", z, ...
    "Precision", options.WorkingPrecision, ...
    "DirectionCount", options.DirectionCount, ...
    "ReferenceSeconds", referenceSeconds, ...
    "VectorizedSeconds", vectorizedSeconds, ...
    "VectorizedRepetitionSeconds", elapsed, ...
    "Speedup", speedup, ...
    "MinimumSpeedup", options.MinimumSpeedup, ...
    "NumericalComparison", comparison, ...
    "ReferenceTrackedArrayBytes", reference.TrackedArrayBytes, ...
    "VectorizedTrackedArrayBytes", candidate.TrackedArrayBytes, ...
    "MaximumScanlineStateBytes", ...
    candidate.MaximumScanlineStateBytes, ...
    "PathCostsStored", false, ...
    "DirectionCountStored", false, ...
    "AllPass", allPass, ...
    "ArrayLayout", "[row,column,label]", ...
    "InvalidCost", "NaN", ...
    "PenaltyModel", candidate.PenaltyModel, ...
    "WorldFrame", "local ENU metres", ...
    "ElevationUnits", "metres");

fprintf("SGM optimization: reference %.3f s, vectorized %.3f s, " ...
    + "%.3fx; exact %s; pass %s\n", ...
    referenceSeconds, vectorizedSeconds, speedup, ...
    string(comparison.Pass), string(report.AllPass));
fprintf("  tracked reference %.3f MiB, vectorized %.3f MiB, " ...
    + "scanline state %.3f MiB\n", ...
    reference.TrackedArrayBytes ./ 2 ^ 20, ...
    candidate.TrackedArrayBytes ./ 2 ^ 20, ...
    candidate.MaximumScanlineStateBytes ./ 2 ^ 20);
if options.OutputFile ~= ""
    save(options.OutputFile, "report", "-v7.3");
end
clear cleanup
end
